// Some portions generated by Claude Code

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;

/**
 * The OMNI strategy must estimate the number of distinct values of the requested join component, not echo the row
 * count. The store holds 1000 rows: 4 predicates x 250 rows, 25 distinct subjects, 50 distinct objects per predicate.
 */
class SketchBasedJoinEstimatorOmniDistinctEstimateTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final int PREDICATES = 4;
	private static final int ROWS_PER_PREDICATE = 250;
	private static final int DISTINCT_SUBJECTS = 25;
	private static final int DISTINCT_OBJECTS_PER_PREDICATE = 50;

	private final List<SketchBasedJoinEstimator> estimators = new ArrayList<>();

	@AfterEach
	void closeEstimators() {
		for (SketchBasedJoinEstimator estimator : estimators) {
			estimator.close();
		}
		estimators.clear();
	}

	@Test
	void allWildcardPredicateDistinctReflectsPredicateCount() {
		SketchBasedJoinEstimator estimator = ingestedEstimator();

		SketchBasedJoinEstimator.JoinEstimate estimate = estimator
				.estimate(SketchBasedJoinEstimator.Component.P, null, null, null, null);

		assertEquals(PREDICATES * ROWS_PER_PREDICATE, estimate.estimate(), PREDICATES * ROWS_PER_PREDICATE * 0.10,
				"all-wildcard row estimate should stay at the statement count");
		assertEquals(PREDICATES, estimate.distinct(), 0.5,
				"all-wildcard predicate distinct must be the predicate count, not the row count");
	}

	@Test
	void allWildcardSubjectDistinctReflectsSubjectCount() {
		SketchBasedJoinEstimator estimator = ingestedEstimator();

		SketchBasedJoinEstimator.JoinEstimate estimate = estimator
				.estimate(SketchBasedJoinEstimator.Component.S, null, null, null, null);

		assertEquals(DISTINCT_SUBJECTS, estimate.distinct(), 1.0,
				"all-wildcard subject distinct must be the subject count, not the row count");
	}

	@Test
	void boundPredicateObjectDistinctReflectsObjectValueCount() {
		SketchBasedJoinEstimator estimator = ingestedEstimator();

		double distinct = estimator.estimateJoinVarDistinctRows(boundPredicatePattern(0), "o");

		assertEquals(DISTINCT_OBJECTS_PER_PREDICATE, distinct, 2.0,
				"distinct objects under a bound predicate must reflect the object value count, not the row count");
	}

	@Test
	void boundPredicateSubjectDistinctReflectsSubjectValueCount() {
		SketchBasedJoinEstimator estimator = ingestedEstimator();

		double distinct = estimator.estimateJoinVarDistinctRows(boundPredicatePattern(0), "s");

		assertEquals(DISTINCT_SUBJECTS, distinct, 1.0,
				"distinct subjects under a bound predicate must reflect the subject value count, not the row count");
	}

	private SketchBasedJoinEstimator ingestedEstimator() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		for (int p = 0; p < PREDICATES; p++) {
			IRI predicate = VF.createIRI("urn:ndv:p:" + p);
			for (int i = 0; i < ROWS_PER_PREDICATE; i++) {
				store.add(VF.createStatement(
						VF.createIRI("urn:ndv:s:" + (i % DISTINCT_SUBJECTS)),
						predicate,
						VF.createIRI("urn:ndv:o:" + p + ":" + (i % DISTINCT_OBJECTS_PER_PREDICATE))));
			}
		}
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, omniConfig());
		estimators.add(estimator);
		estimator.rebuild();
		return estimator;
	}

	private static StatementPattern boundPredicatePattern(int predicateIndex) {
		return new StatementPattern(new Var("s"),
				new Var("p", VF.createIRI("urn:ndv:p:" + predicateIndex)),
				new Var("o"));
	}

	private static SketchBasedJoinEstimator.Config omniConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.OMNI)
				.withNominalEntries(512)
				.withSubjectBucketCount(512)
				.withPredicateBucketCount(64)
				.withObjectBucketCount(512)
				.withContextBucketCount(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(60_000);
	}
}
